func:
const apiSpec = {
  openapi: '3.0.3',
  info: {
    title: 'AI Insight ORCE API',
    version: '0.8.0',
    description: 'Node-RED ORCE runtime endpoints for AI insight generation and retrieval. ReDoc/Swagger include field-level accepted values and behavior details.',
  },
  servers: [
    {
      url: '/',
      description: 'Local ORCE runtime',
    },
  ],
  tags: [
    { name: 'health', description: 'Service health checks' },
    { name: 'insights', description: 'Insight generation and retrieval' },
    { name: 'docs', description: 'OpenAPI artifacts' },
  ],
  components: {
    parameters: {
      AgreementHeader: {
        name: 'x-agreement-id',
        in: 'header',
        required: true,
        schema: { type: 'string' },
        description: 'Agreement identifier used by policy and rate limiting.',
      },
      AssetHeader: {
        name: 'x-asset-id',
        in: 'header',
        required: true,
        schema: { type: 'string' },
        description: 'Asset identifier used by policy checks.',
      },
      UserRolesHeader: {
        name: 'x-user-roles',
        in: 'header',
        required: true,
        schema: { type: 'string' },
        description: 'Comma-separated roles. Must include ai_insight_consumer.',
      },
      CacheBypassHeader: {
        name: 'x-insight-cache-bypass',
        in: 'header',
        required: false,
        schema: { type: 'string', enum: ['true', 'false'] },
        description: 'Optional cache bypass flag. Use true to force recomputation.',
      },
      OutputIdPath: {
        name: 'output_id',
        in: 'path',
        required: true,
        schema: { type: 'string' },
        description: 'Output identifier generated in insight metadata.',
      },
    },
    headers: {
      RetryAfter: {
        description: 'Seconds to wait before retrying after rate limit.',
        schema: { type: 'string' },
      },
    },
    schemas: {
      ErrorDetail: {
        type: 'object',
        properties: {
          detail: { type: 'string' },
        },
        required: ['detail'],
        additionalProperties: false,
      },
      HealthResponse: {
        type: 'object',
        properties: {
          status: { type: 'string', example: 'ok' },
          service: { type: 'string', example: 'ai-insight-service' },
        },
        required: ['status', 'service'],
        additionalProperties: true,
      },
      InsightMetadata: {
        type: 'object',
        properties: {
          output_id: { type: 'string', format: 'uuid' },
          llm_model: { type: 'string' },
          timestamp: { type: 'string', format: 'date-time' },
          llm_used: { type: 'boolean' },
          agreement_id: { type: 'string' },
          asset_id: { type: 'string' },
          llm_error: { type: ['string', 'null'] },
        },
        required: ['output_id', 'llm_model', 'timestamp', 'llm_used', 'agreement_id', 'asset_id', 'llm_error'],
        additionalProperties: false,
      },
      InsightResponse: {
        type: 'object',
        properties: {
          insight_type: { type: 'string', enum: ['anomaly-report', 'energy-summary', 'city-status'] },
          summary: { type: 'string' },
          key_findings: {
            type: 'array',
            items: { type: 'string' },
          },
          recommendations: {
            type: 'array',
            items: { type: 'string' },
          },
          metadata: { $ref: '#/components/schemas/InsightMetadata' },
          data: {},
        },
        required: ['insight_type', 'summary', 'key_findings', 'recommendations', 'metadata', 'data'],
        additionalProperties: false,
      },
      AnomalyReportRequest: {
        type: 'object',
        properties: {
          start_ts: { type: 'string', format: 'date-time', description: 'Start timestamp (inclusive). Must be earlier than end_ts.' },
          end_ts: { type: 'string', format: 'date-time', description: 'End timestamp (exclusive upper bound). Must be later than start_ts.' },
          timezone: { type: 'string', default: 'UTC', description: 'Timezone label for context and narrative. Example: UTC.' },
          robust_z_threshold: { type: 'number', minimum: 0.000001, default: 3.5, description: 'Anomaly sensitivity threshold. Accepted values: any number > 0.' },
          include_data: { type: 'boolean', default: false, description: 'When true, include detailed context in response.data; when false, data is null.' },
        },
        required: ['start_ts', 'end_ts'],
        additionalProperties: true,
      },
      EnergySummaryRequest: {
        type: 'object',
        properties: {
          start_ts: { type: 'string', format: 'date-time', description: 'Start timestamp (inclusive). Must be earlier than end_ts.' },
          end_ts: { type: 'string', format: 'date-time', description: 'End timestamp (exclusive upper bound). Must be later than start_ts.' },
          timezone: { type: 'string', default: 'UTC', description: 'Timezone label for context and narrative. Example: UTC.' },
          forecast_alpha: { type: 'number', minimum: 0.000001, maximum: 1, default: 0.6, description: 'Forecast smoothing factor. Accepted range: (0, 1].' },
          trend_epsilon: { type: 'number', minimum: 0, default: 0.02, description: 'Trend sensitivity epsilon. Accepted values: >= 0.' },
          daily_overview_strategy: {
            type: 'string',
            enum: ['strict_daily', 'fallback_hourly'],
            default: 'strict_daily',
            description: 'Accepted values: strict_daily (only daily views), fallback_hourly (fallback to hourly aggregation when daily views are missing).',
          },
          include_data: { type: 'boolean', default: false, description: 'When true, include detailed context in response.data; when false, data is null.' },
        },
        required: ['start_ts', 'end_ts'],
        additionalProperties: true,
      },
      CityStatusRequest: {
        type: 'object',
        properties: {
          start_ts: { type: 'string', format: 'date-time', description: 'Start timestamp (inclusive). Must be earlier than end_ts.' },
          end_ts: { type: 'string', format: 'date-time', description: 'End timestamp (exclusive upper bound). Must be later than start_ts.' },
          timezone: { type: 'string', default: 'UTC', description: 'Timezone label for context and narrative. Example: UTC.' },
          include_data: { type: 'boolean', default: false, description: 'When true, include detailed context in response.data; when false, data is null.' },
        },
        required: ['start_ts', 'end_ts'],
        additionalProperties: true,
      },
      LatestInsightEntry: {
        type: 'object',
        properties: {
          cached_at: { type: 'string', format: 'date-time' },
          output: { $ref: '#/components/schemas/InsightResponse' },
        },
        required: ['cached_at', 'output'],
        additionalProperties: false,
      },
      LatestInsightsResponse: {
        type: 'object',
        properties: {
          latest: {
            type: 'object',
            properties: {
              'energy-summary': {
                oneOf: [
                  { $ref: '#/components/schemas/LatestInsightEntry' },
                  { type: 'null' }
                ]
              },
              'anomaly-report': {
                oneOf: [
                  { $ref: '#/components/schemas/LatestInsightEntry' },
                  { type: 'null' }
                ]
              },
              'city-status': {
                oneOf: [
                  { $ref: '#/components/schemas/LatestInsightEntry' },
                  { type: 'null' }
                ]
              }
            },
            required: ['energy-summary', 'anomaly-report', 'city-status'],
            additionalProperties: false,
          },
        },
        required: ['latest'],
        additionalProperties: false,
      },
      AIOutputEntityResponse: {
        type: 'object',
        properties: {
          id: { type: 'string', format: 'uuid' },
          insight_type: { type: 'string' },
          agreement_id: { type: 'string' },
          asset_id: { type: 'string' },
          input_data: { type: 'object', additionalProperties: true },
          llm_model: { type: 'string' },
          output_text: { type: 'string' },
          structured_output: { type: 'object', additionalProperties: true },
          timestamp: { type: 'string', format: 'date-time' },
        },
        required: ['id', 'insight_type', 'agreement_id', 'asset_id', 'input_data', 'llm_model', 'output_text', 'structured_output', 'timestamp'],
        additionalProperties: false,
      },
    },
    responses: {
      Error400: {
        description: 'Invalid request payload.',
        content: {
          'application/json': {
            schema: { $ref: '#/components/schemas/ErrorDetail' },
            examples: {
              invalidPayload: { value: { detail: 'Request body must be valid JSON' } },
            },
          },
        },
      },
      Error403: {
        description: 'Policy denied request.',
        content: {
          'application/json': {
            schema: { $ref: '#/components/schemas/ErrorDetail' },
            examples: {
              denied: { value: { detail: 'Policy denied: missing required role ai_insight_consumer' } },
            },
          },
        },
      },
      Error404: {
        description: 'Requested entity not found.',
        content: {
          'application/json': {
            schema: { $ref: '#/components/schemas/ErrorDetail' },
            examples: {
              notFound: { value: { detail: 'Output not found' } },
            },
          },
        },
      },
      Error429: {
        description: 'Agreement rate limit exceeded.',
        headers: {
          'Retry-After': { $ref: '#/components/headers/RetryAfter' },
        },
        content: {
          'application/json': {
            schema: { $ref: '#/components/schemas/ErrorDetail' },
            examples: {
              rateLimited: { value: { detail: 'Agreement rate limit exceeded' } },
            },
          },
        },
      },
      Error500: {
        description: 'Unhandled internal runtime error.',
        content: {
          'application/json': {
            schema: { $ref: '#/components/schemas/ErrorDetail' },
            examples: {
              internal: { value: { detail: 'internal_error' } },
            },
          },
        },
      },
      Error502: {
        description: 'Upstream dependency failure (Trino/OIDC/LLM).',
        content: {
          'application/json': {
            schema: { $ref: '#/components/schemas/ErrorDetail' },
            examples: {
              upstream: { value: { detail: 'Upstream dependency failure while generating insight' } },
            },
          },
        },
      },
    },
  },
  paths: {
    '/api/v1/health': {
      get: {
        tags: ['health'],
        summary: 'Health check',
        description: 'Returns ORCE runtime health status.',
        responses: {
          '200': {
            description: 'Health response.',
            content: {
              'application/json': {
                schema: { $ref: '#/components/schemas/HealthResponse' },
                examples: {
                  ok: {
                    value: {
                      status: 'ok',
                      service: 'ai-insight-service',
                    },
                  },
                },
              },
            },
          },
          '500': { $ref: '#/components/responses/Error500' },
        },
      },
    },
    '/api/v1/insights/anomaly-report': {
      post: {
        tags: ['insights'],
        summary: 'Generate anomaly report insight',
        parameters: [
          { $ref: '#/components/parameters/AgreementHeader' },
          { $ref: '#/components/parameters/AssetHeader' },
          { $ref: '#/components/parameters/UserRolesHeader' },
          { $ref: '#/components/parameters/CacheBypassHeader' },
        ],
        requestBody: {
          required: true,
          content: {
            'application/json': {
              schema: { $ref: '#/components/schemas/AnomalyReportRequest' },
              examples: {
                defaultWindow: {
                  value: {
                    start_ts: '2026-03-01T00:00:00Z',
                    end_ts: '2026-03-02T00:00:00Z',
                    timezone: 'UTC',
                    robust_z_threshold: 3.5,
                    include_data: false,
                  },
                },
              },
            },
          },
        },
        responses: {
          '200': {
            description: 'Insight generated successfully.',
            content: {
              'application/json': {
                schema: { $ref: '#/components/schemas/InsightResponse' },
              },
            },
          },
          '400': { $ref: '#/components/responses/Error400' },
          '403': { $ref: '#/components/responses/Error403' },
          '429': { $ref: '#/components/responses/Error429' },
          '502': { $ref: '#/components/responses/Error502' },
        },
      },
    },
    '/api/v1/insights/energy-summary': {
      post: {
        tags: ['insights'],
        summary: 'Generate energy summary insight',
        parameters: [
          { $ref: '#/components/parameters/AgreementHeader' },
          { $ref: '#/components/parameters/AssetHeader' },
          { $ref: '#/components/parameters/UserRolesHeader' },
          { $ref: '#/components/parameters/CacheBypassHeader' },
        ],
        requestBody: {
          required: true,
          content: {
            'application/json': {
              schema: { $ref: '#/components/schemas/EnergySummaryRequest' },
              examples: {
                strictDaily: {
                  value: {
                    start_ts: '2026-03-01T00:00:00Z',
                    end_ts: '2026-03-02T00:00:00Z',
                    timezone: 'UTC',
                    forecast_alpha: 0.6,
                    trend_epsilon: 0.02,
                    daily_overview_strategy: 'strict_daily',
                    include_data: false,
                  },
                },
              },
            },
          },
        },
        responses: {
          '200': {
            description: 'Insight generated successfully.',
            content: {
              'application/json': {
                schema: { $ref: '#/components/schemas/InsightResponse' },
              },
            },
          },
          '400': { $ref: '#/components/responses/Error400' },
          '403': { $ref: '#/components/responses/Error403' },
          '429': { $ref: '#/components/responses/Error429' },
          '502': { $ref: '#/components/responses/Error502' },
        },
      },
    },
    '/api/v1/insights/city-status': {
      post: {
        tags: ['insights'],
        summary: 'Generate city status insight',
        parameters: [
          { $ref: '#/components/parameters/AgreementHeader' },
          { $ref: '#/components/parameters/AssetHeader' },
          { $ref: '#/components/parameters/UserRolesHeader' },
          { $ref: '#/components/parameters/CacheBypassHeader' },
        ],
        requestBody: {
          required: true,
          content: {
            'application/json': {
              schema: { $ref: '#/components/schemas/CityStatusRequest' },
              examples: {
                defaultWindow: {
                  value: {
                    start_ts: '2026-03-01T00:00:00Z',
                    end_ts: '2026-03-02T00:00:00Z',
                    timezone: 'UTC',
                    include_data: false,
                  },
                },
              },
            },
          },
        },
        responses: {
          '200': {
            description: 'Insight generated successfully.',
            content: {
              'application/json': {
                schema: { $ref: '#/components/schemas/InsightResponse' },
              },
            },
          },
          '400': { $ref: '#/components/responses/Error400' },
          '403': { $ref: '#/components/responses/Error403' },
          '429': { $ref: '#/components/responses/Error429' },
          '502': { $ref: '#/components/responses/Error502' },
        },
      },
    },
    '/api/v1/insights/latest': {
      get: {
        tags: ['insights'],
        summary: 'Get latest insight outputs by type',
        responses: {
          '200': {
            description: 'Latest insight map.',
            content: {
              'application/json': {
                schema: { $ref: '#/components/schemas/LatestInsightsResponse' },
              },
            },
          },
          '500': { $ref: '#/components/responses/Error500' },
        },
      },
    },
    '/api/ai/outputs/{output_id}': {
      get: {
        tags: ['insights'],
        summary: 'Get persisted output entity by id',
        parameters: [
          { $ref: '#/components/parameters/OutputIdPath' },
        ],
        responses: {
          '200': {
            description: 'Output entity returned successfully.',
            content: {
              'application/json': {
                schema: { $ref: '#/components/schemas/AIOutputEntityResponse' },
              },
            },
          },
          '404': { $ref: '#/components/responses/Error404' },
          '500': { $ref: '#/components/responses/Error500' },
        },
      },
    },
  },
};

msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = apiSpec;
return msg;

msg.statusCode = 200;
msg.headers = { 'Content-Type': 'text/html; charset=utf-8' };
msg.payload = `<!doctype html>
<html>
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>AI Insight ORCE API Docs</title>
  <link rel="stylesheet" href="https://unpkg.com/swagger-ui-dist@5/swagger-ui.css" />
  <style>
    html, body { margin: 0; padding: 0; background: #fafafa; }
    #swagger-ui { max-width: 1200px; margin: 0 auto; }
  </style>
</head>
<body>
  <div id="swagger-ui"></div>
  <script src="https://unpkg.com/swagger-ui-dist@5/swagger-ui-bundle.js"></script>
  <script>
    window.ui = SwaggerUIBundle({
      url: '/openapi.json',
      dom_id: '#swagger-ui',
      deepLinking: true,
      displayRequestDuration: true,
      defaultModelsExpandDepth: 2,
      docExpansion: 'list',
    });
  </script>
</body>
</html>`;
return msg;

if (!msg.res) {
    return null;
}

const alreadySent = !!(msg.res.headersSent || (msg.res._res && (msg.res._res.headersSent || msg.res._res.writableEnded)));
if (alreadySent) {
    return null;
}

msg.statusCode = 500;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = { detail: 'internal_error' };
return msg;
